<template>
  <div
    class="modal fade"
    id="productModal"
    tabindex="-1"
    role="dialog"
    aria-labelledby="exampleModalLabel"
    aria-hidden="true"
    ref="modal">
    <div class="modal-dialog modal-xl" role="document">
      <div class="modal-content border-0">
        <div class="modal-header bg-dark text-white">
          <h5 class="modal-title" id="exampleModalLabel">
            <!-- <span>{{product.title }}</span> -->
          </h5>
          <button type="button" class="btn-close"
                  data-bs-dismiss="modal" aria-label="Close"></button>
        </div>
        <div class="modal-body">
          <div class="row">
            <div class="col-sm-6">
              <img class="img-fluid" :src="product.imageUrl" alt="">
            </div>
            <div class="col-sm-6">
              <span class="badge bg-primary rounded-pill">{{}}</span>
              <p>商品描述：{{product.description}}</p>
              <p>商品內容：{{product.content }}</p>
                  <!-- 如果有價格就顯示原價沒有就顯示原價 -->
              <del class="h6" v-if="product.price">原價 {{product.origin_price}} 元</del>
              <div class="h5" v-if="product.price">現在只要 {{ product.price }} 元</div>
              <div>
                <div class="input-group">
                  <input type="number" min="1" class="form-control" v-model.number="qty">
                  <button type="button" class="btn btn-primary" @click="addCartModal"
                  :disabled=" loadingStatus === product.id">加入購物車</button>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import Modal from 'bootstrap/js/dist/modal';

export default {
  props: ['product'],
  data() {
    return {
      modal: ' ',
      tempProduct: {},
      qty: 1,
    };
  },
  watch: {
    // 注意這邊避免單向數據流
    product() {
      this.tempProduct = this.product;
    },
  },
  mounted() {
    this.modal = new Modal(this.$refs.modal, {
      keyboard: false,
      backdrop: 'static',
    });
  },
  methods: {
    openModal() {
      this.modal.show();
    },
    addCartModal() {
      this.$emit('emit-addCart', this.tempProduct, this.qty);
    },
    closeModal() {
      this.modal.hide();
    },
  },
};
</script>
